import{c as t,Q as a,j as s,m as i}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"@garrytan — Thin Harness, Fat Skills：AI 生產力 100x 差距來自架構設計","description":"","frontmatter":{"title":"@garrytan — Thin Harness, Fat Skills：AI 生產力 100x 差距來自架構設計","author":"@garrytan（Garry Tan｜YC President & CEO｜799,684 followers）","date":"2026-04-11T00:00:00.000Z","source":"https://x.com/garrytan/status/2042925773300908103","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-11-@garrytan-908103.md","filePath":"research/tweets/2026-04-11-@garrytan-908103.md","lastUpdated":1779894392000}'),n={name:"research/tweets/2026-04-11-@garrytan-908103.md"};function r(o,e,l,h,d,p){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="garrytan-—-thin-harness-fat-skills-ai-生產力-100x-差距來自架構設計" tabindex="-1">@garrytan — Thin Harness, Fat Skills：AI 生產力 100x 差距來自架構設計 <a class="header-anchor" href="#garrytan-—-thin-harness-fat-skills-ai-生產力-100x-差距來自架構設計" aria-label="Permalink to &quot;@garrytan — Thin Harness, Fat Skills：AI 生產力 100x 差距來自架構設計&quot;">​</a></h1><p><strong>來源</strong>: <a href="https://x.com/garrytan/status/2042925773300908103" target="_blank" rel="noreferrer">https://x.com/garrytan/status/2042925773300908103</a><br><strong>作者</strong>: @garrytan（Garry Tan｜YC President &amp; CEO｜799,684 followers）<br><strong>日期</strong>: 2026-04-11<br><strong>統計</strong>: 👍 4,092 · 🔁 448 · 🔖 11,347 · 👁 1,486,212<br><strong>收錄</strong>: 2026-05-13 · <strong>評分: 8.8 / 10</strong><br><strong>整合決策</strong>: Agent（<code>thin-harness-fat-skills</code> pattern）</p><hr><h2 id="原文全文-twitter-article" tabindex="-1">原文全文（Twitter Article） <a class="header-anchor" href="#原文全文-twitter-article" aria-label="Permalink to &quot;原文全文（Twitter Article）&quot;">​</a></h2><p><strong>標題</strong>: Thin Harness, Fat Skills</p><p>Steve Yegge says people using AI coding agents are &quot;10x to 100x as productive as engineers using Cursor and chat today, and roughly 1000x as productive as Googlers were back in 2005.&quot;</p><p>That&#39;s a real number. I&#39;ve seen it. I&#39;ve lived it. But when people hear it, they reach for the wrong explanation. Better models. Smarter Claude. More parameters. The 2x people and the 100x people are using the same models. The difference isn&#39;t intelligence. It&#39;s architecture — and it fits on an index card.</p><h3 id="the-harness-is-the-product" tabindex="-1">The harness is the product <a class="header-anchor" href="#the-harness-is-the-product" aria-label="Permalink to &quot;The harness is the product&quot;">​</a></h3><p>On March 31, 2026, Anthropic accidentally shipped the entire source code for Claude Code to the npm registry. 512,000 lines. I read it. It confirmed everything I&#39;d been teaching at YC: the secret isn&#39;t the model. It&#39;s the thing wrapping the model.</p><p>Live repo context. Prompt caching. Purpose-built tools. Context bloat minimization. Structured session memory. Parallel sub-agents. None of that makes the model smarter. All of it gives the model the right context, at the right time, without drowning it in noise.</p><p>That wrapper is called the <strong>harness</strong>. And the question every AI builder should be asking is: what goes in the harness, and what stays out? The answer has a specific shape. I call it <strong>thin harness, fat skills</strong>.</p><h3 id="five-definitions" tabindex="-1">Five definitions <a class="header-anchor" href="#five-definitions" aria-label="Permalink to &quot;Five definitions&quot;">​</a></h3><p>The bottleneck is never the model&#39;s intelligence. Models already know how to reason, synthesize, and write code. They fail because they don&#39;t understand your data — your schema, your conventions, the particular shape of your problem. Five definitions fix this.</p><p><strong>1. Skill files</strong></p><p>A skill file is a reusable markdown document that teaches the model how to do something. Not what to do — the user supplies that. The skill supplies the process.</p><p>Here&#39;s the key insight most people miss: a skill file works like a method call. It takes parameters. You invoke it with different arguments. The same procedure produces radically different capabilities depending on what you pass in.</p><p>Consider a skill called /investigate. It has seven steps: scope the dataset, build a timeline, diarize every document, synthesize, argue both sides, cite sources. It takes three parameters: TARGET, QUESTION, and DATASET. Point it at a safety scientist and 2.1 million discovery emails, and you get a medical research analyst determining whether a whistleblower was silenced. Point it at a shell company and FEC filings, and you get a forensic investigator tracing coordinated campaign donations.</p><p>Same skill. Same seven steps. Same markdown file. The skill describes a process of judgment. The invocation supplies the world.</p><p>This is not prompt engineering. This is software design, using markdown as the programming language and human judgment as the runtime. Markdown is, in fact, a more perfect encapsulation of capability than rigid source code, because it describes process, judgment, and context in the language the model already thinks in.</p><p><strong>2. The harness</strong></p><p>The harness is the program that runs the LLM. It does four things: runs the model in a loop, reads and writes your files, manages context, and enforces safety. That&#39;s it. That&#39;s the &quot;thin.&quot;</p><p>The anti-pattern is a fat harness with thin skills. You&#39;ve seen it: 40+ tool definitions eating half the context window. God-tools with 2-to-5-second MCP round-trips. REST API wrappers that turn every endpoint into a separate tool. Three times the tokens, three times the latency, three times the failure rate.</p><p>What you want instead is purpose-built tooling that&#39;s fast and narrow. A Playwright CLI that does each browser operation in 100 milliseconds, not a Chrome MCP that takes 15 seconds for screenshot-find-click-wait-read. That&#39;s 75x faster. Software doesn&#39;t have to be precious anymore. Build exactly what you need, and nothing else.</p><p><strong>3. Resolvers</strong></p><p>A resolver is a routing table for context. When task type X appears, load document Y first.</p><p>Skills tell the model how. Resolvers tell it what to load and when. A developer changes a prompt. Without the resolver, they ship it. With the resolver, the model reads docs/EVALS.md first — which says: run the eval suite, compare scores, if accuracy drops more than 2%, revert and investigate. The developer didn&#39;t know the eval suite existed. The resolver loaded the right context at the right moment.</p><p>Claude Code has a built-in resolver. Every skill has a description field, and the model matches user intent to skill descriptions automatically. You never have to remember that /ship exists. The description is the resolver.</p><p>A confession: my CLAUDE.md was 20,000 lines. Every quirk, every pattern, every lesson I&#39;d ever encountered. Completely ridiculous. The model&#39;s attention degraded. Claude Code literally told me to cut it back. The fix was about 200 lines — just pointers to documents. The resolver loads the right one when it matters. Twenty thousand lines of knowledge, accessible on demand, without polluting the context window.</p><p><strong>4. Latent vs. deterministic</strong></p><p>Every step in your system is one or the other, and confusing them is the most common mistake in agent design.</p><p>Latent space is where intelligence lives. The model reads, interprets, decides. Judgment. Synthesis. Pattern recognition.</p><p>Deterministic is where trust lives. Same input, same output. Every time. SQL queries. Compiled code. Arithmetic.</p><p>An LLM can seat 8 people at a dinner table, accounting for personalities and social dynamics. Ask it to seat 800 and it will hallucinate a seating chart that looks plausible but is completely wrong. That&#39;s a deterministic problem — combinatorial optimization — forced into latent space. The worst systems put the wrong work on the wrong side of this line. The best systems are ruthless about it.</p><p><strong>5. Diarization</strong></p><p>Diarization is the step that makes AI useful for real knowledge work. The model reads everything about a subject and writes a structured profile — a single page of judgment distilled from dozens or hundreds of documents.</p><p>No SQL query produces this. No RAG pipeline produces this. The model has to actually read, hold contradictions in mind, notice what changed and when, and synthesize structured intelligence. It&#39;s the difference between a database lookup and an analyst&#39;s brief.</p><h3 id="the-architecture" tabindex="-1">The architecture <a class="header-anchor" href="#the-architecture" aria-label="Permalink to &quot;The architecture&quot;">​</a></h3><p>These five concepts compose into a simple three-layer architecture.</p><p>Fat skills sit on top: markdown procedures that encode judgment, process, and domain knowledge. This is where 90% of the value lives.</p><p>A thin CLI harness sits in the middle: about 200 lines of code. JSON in, text out. Read-only by default.</p><p>Your application sits on the bottom: QueryDB, ReadDoc, Search, Timeline — the deterministic foundation.</p><p>The principle is directional. Push intelligence up into skills. Push execution down into deterministic tooling. Keep the harness thin. When you do this, every improvement to the model automatically improves every skill, while the deterministic layer stays perfectly reliable.</p><h3 id="the-system-that-learns" tabindex="-1">The system that learns <a class="header-anchor" href="#the-system-that-learns" aria-label="Permalink to &quot;The system that learns&quot;">​</a></h3><p>Let me show you all five definitions working together. Not in theory — in an actual system we&#39;re building at YC.</p><p>Chase Center. July 2026. Six thousand founders at Startup School. Each one has a structured application, questionnaire answers, transcripts from 1:1 advisor chats, and public signals: posts on X, GitHub commits, Claude Code transcripts showing how fast they ship.</p><p>The traditional approach: a program team of 15 reads applications, makes gut calls, updates a spreadsheet. It works at 200 founders. It breaks at 6,000.</p><p><strong>Enrichment</strong>. A skill called /enrich-founder pulls all sources, runs enrichments, diarizes, and highlights the gap between what founders say and what they&#39;re actually building. The deterministic layer handles SQL lookups, GitHub stats, browser tests on demo URLs, social signal pulls.</p><p>The diarization output catches things no keyword search would find:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FOUNDER: Maria Santos</span></span>
<span class="line"><span>COMPANY: Contrail (contrail.dev)</span></span>
<span class="line"><span>SAYS: &quot;Datadog for AI agents&quot;</span></span>
<span class="line"><span>ACTUALLY BUILDING: 80% of commits are in billing module.</span></span>
<span class="line"><span>  She&#39;s building a FinOps tool disguised as observability.</span></span></code></pre></div><p><strong>Matching</strong>. Three invocations of the same matching skill, three completely different strategies:</p><ul><li><code>/match-breakout</code>: 1,200 founders, clusters by sector affinity, 30 per room</li><li><code>/match-lunch</code>: 600 founders, serendipity matching across sectors, 8 per table — LLM invents themes, deterministic algorithm assigns seats</li><li><code>/match-live</code>: whoever is in the building now, nearest-neighbor embedding, 200ms, 1:1 pairs, no repeats</li></ul><p><strong>The learning loop</strong>. After the event, an /improve skill reads NPS surveys, diarizes the mediocre responses — not the bad ones, the &quot;OK&quot; ones — and extracts patterns. Then it proposes new rules and writes them back into the matching skills:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>When attendee says &quot;AI infrastructure&quot;</span></span>
<span class="line"><span>    but startup is 80%+ billing code:</span></span>
<span class="line"><span>    → Classify as FinTech, not AI Infra.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>When two attendees in same group</span></span>
<span class="line"><span>    already know each other:</span></span>
<span class="line"><span>    → Penalize proximity.</span></span>
<span class="line"><span>       Prioritize novel introductions.</span></span></code></pre></div><p>July event: 12% &quot;OK&quot; ratings. Next event: 4%. The skill file learned what &quot;OK&quot; actually meant, and the system got better without anyone rewriting code.</p><h3 id="skills-are-permanent-upgrades" tabindex="-1">Skills are permanent upgrades <a class="header-anchor" href="#skills-are-permanent-upgrades" aria-label="Permalink to &quot;Skills are permanent upgrades&quot;">​</a></h3><blockquote><p>You are not allowed to do one-off work. If I ask you to do something and it&#39;s the kind of thing that will need to happen again, you must: do it manually the first time on 3 to 10 items. Show me the output. If I approve, codify it into a skill file. If it should run automatically, put it on a cron. The test: if I have to ask you for something twice, you failed.</p></blockquote><p>A thousand likes and twenty-five hundred bookmarks. People thought it was a prompt engineering trick. It&#39;s not. It&#39;s the architecture I&#39;ve been describing. Every skill you write is a permanent upgrade to your system. It never degrades. It never forgets. It runs at 3 AM while you sleep. And when the next model drops, every skill instantly gets better — the judgment in the latent steps improves while the deterministic steps stay perfectly reliable.</p><p>That&#39;s how you get Yegge&#39;s 100x. Not a smarter model. Fat skills, thin harness, and the discipline to codify everything.</p><p>The system compounds. Build it once. It runs forever.</p><hr><h2 id="分析" tabindex="-1">分析 <a class="header-anchor" href="#分析" aria-label="Permalink to &quot;分析&quot;">​</a></h2><h3 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h3><p>AI 生產力 100x 差距來自 thin harness + fat skills 架構設計，而非模型智能；5 個定義（skill files、harness、resolvers、latent vs. deterministic、diarization）構成可直接套用的三層框架。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>Thin Harness, Fat Skills</strong>: harness 只做 4 件事（run model loop, read/write files, manage context, enforce safety）；智能押注在 skill files；Fat harness with thin skills 是反模式（40+ tools、MCP round-trips、3x tokens/latency/failure rate）</li><li><strong>Skill file as method call</strong>: 同一個 <code>/investigate</code> skill + 不同參數 = 完全不同能力；markdown 是比 source code 更完美的能力封裝，因為它描述的是判斷過程而非固定指令</li><li><strong>Latent vs. Deterministic 分野</strong>: 混淆兩者是最常見的 agent 設計錯誤；combinatorial optimization 是 deterministic 問題，不能放進 latent space（8 人 vs 800 人座位案例）</li><li><strong>Diarization（摘要蒸餾）</strong>: 讀取所有文件後生成單頁結構化 profile，這是 RAG/SQL 無法替代的 LLM 核心能力（「says vs. actually building」gap detection）</li><li><strong>Self-improving skill loop</strong>: <code>/improve</code> skill 讀取 NPS → 提取規則 → 回寫 skill file；YC Startup School event NPS 從 12% &quot;OK&quot; 降至 4%</li></ol><h3 id="關鍵數字" tabindex="-1">關鍵數字 <a class="header-anchor" href="#關鍵數字" aria-label="Permalink to &quot;關鍵數字&quot;">​</a></h3><ul><li>Steve Yegge 100x 生產力（同模型、不同架構）</li><li>Claude Code 原始碼洩露：512,000 行（2026-03-31）</li><li>CLAUDE.md 20,000 行 → 200 行（resolver 架構後）</li><li>Playwright CLI 100ms vs Chrome MCP 15s = <strong>75x 速度差距</strong></li><li>YC Startup School：6,000 founders，傳統 15 人團隊在 200 人規模時就能運作，6,000 人時崩潰</li><li>NPS &quot;OK&quot; 評分：12%（首次）→ 4%（第二次）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li>5 個定義環環相扣，YC Startup School 案例提供完整的端對端驗證，說服力強；「說的 vs 實際建的」gap detection 案例特別具體</li><li>Skill file 自我改寫（/improve loop）的版本控制與審核問題未提：若 /improve 寫錯規則導致回歸怎麼辦？需要人工審核閘道設計</li><li>「200 行 thin harness」是 Garry 的 GStack 特定實作標準，規模化後 observability、tracing、rate limiting 需求會讓 harness 不得不增厚</li></ol><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A 可行動性 (30%)</td><td>9</td><td>5 個定義 + 三層架構可直接套用；/investigate 範例完整可複製</td></tr><tr><td>B 創新性 (20%)</td><td>9</td><td>Latent/Deterministic 分野 + diarization + self-improving loop 整合為統一框架</td></tr><tr><td>C 證據品質 (20%)</td><td>8</td><td>YC 6,000 founders 案例、NPS 12%→4%、75x 速度差距均有具體數字</td></tr><tr><td>D 技術深度 (15%)</td><td>9</td><td>三層架構、5 定義、具體 CLI 設計建議、matching strategy 三變體</td></tr><tr><td>E 泛化性 (15%)</td><td>9</td><td>框架適用任何 knowledge work agent 設計</td></tr></tbody></table><p><strong>加權總分</strong>: 9×0.3 + 9×0.2 + 8×0.2 + 9×0.15 + 9×0.15 = 2.7+1.8+1.6+1.35+1.35 = <strong>8.8</strong></p>`,73)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
